import React from "react";
import { Link } from "react-router-dom";

const ProductItem = ({ product }) => {
  const totalStars = 5;

  return (
    <div className="col-sm-12 col-md-6 col-lg-3 my-3">
      <div className="card p-3 rounded h-100">
        {/* Product Image */}
        <img
          className="card-img-top mx-auto product-image"
          src={product?.images?.[0]?.url || "/images/default_product.png"}
          alt={product?.name}
        />

        <div className="card-body d-flex flex-column">
          {/* Product Name */}
          <h5 className="card-title">
            <Link to={`/product/${product?._id}`}>{product?.name}</Link>
          </h5>

          {/* ⭐ Star Ratings */}
          <div className="ratings mt-auto d-flex align-items-center">
            <div>
              {[...Array(totalStars)].map((_, index) => {
                const rating = product?.ratings || 0;
                if (index < Math.floor(rating)) {
                  return <i key={index} className="fa fa-star star-active"></i>;
                } else if (index < Math.ceil(rating) && rating % 1 !== 0) {
                  return (
                    <i key={index} className="fa fa-star-half-o star-active"></i>
                  );
                } else {
                  return <i key={index} className="fa fa-star star-inactive"></i>;
                }
              })}
            </div>
            <span id="no_of_reviews" className="pt-2 ps-2">
              {product?.numOfReviews || 0} Reviews
            </span>
          </div>

          {/* Price */}
          <p className="card-text mt-2">
            ${product?.price?.toFixed(2) || "0.00"}
          </p>

          {/* View Details Button */}
          <Link
            to={`/product/${product?._id}`}
            id="view_btn"
            className="btn btn-primary w-100"
          >
            View Details
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ProductItem;
